-- ================================================================
-- schema-v19-descriptions-attractions.sql — 100 Attractions (500~1000자)
-- title_en from schema-v8 INSERT
-- ================================================================

UPDATE challenges SET description_en = 'Angkor Wat is the world''s largest religious monument and the heart of the 12th-century Khmer Empire. The temple complex spans over 400 hectares and features the iconic five towers, bas-reliefs depicting Hindu epics, and the surrounding jungle. UNESCO-listed and Cambodia''s national symbol, it is best experienced at sunrise. Selected for our World 100 as the greatest surviving ancient temple complex and a masterpiece of human creativity.' WHERE category = 'attractions' AND title_en = 'Angkor Wat';

UPDATE challenges SET description_en = 'The plains of Bagan hold over 2,000 Buddhist temples and pagodas on the Irrawaddy River. Sunrise from a temple or hot-air balloon offers one of the world''s most spectacular views. The monuments date from the 9th to 13th centuries. Selected for our World 100 as one of the most dramatic archaeological landscapes and spiritual sites on Earth.' WHERE category = 'attractions' AND title_en = 'Bagan Temples';

UPDATE challenges SET description_en = 'The Great Wall of China stretches over 21,000 km across northern China. Built over centuries to defend against invasions, the Ming-era sections such as Mutianyu and Badaling are the best preserved. Walking the wall offers sweeping views of mountains and history. Selected for our World 100 as the world''s most iconic fortification and a symbol of human ambition.' WHERE category = 'attractions' AND title_en = 'Great Wall of China';

UPDATE challenges SET description_en = 'Machu Picchu is the 15th-century Inca citadel perched at 2,430 m in the Peruvian Andes. Reached by the Inca Trail or train, it features terraces, temples, and the Intihuatana stone. The site was unknown to the outside world until 1911. Selected for our World 100 as the most dramatic and mysterious archaeological site in the Americas.' WHERE category = 'attractions' AND title_en = 'Machu Picchu';

UPDATE challenges SET description_en = 'Petra is the rose-red rock-cut city in Jordan, carved by the Nabataeans over 2,000 years ago. The Treasury (Al-Khazneh) at the end of the Siq is iconic; the Monastery and Royal Tombs extend the wonder. Best seen at dawn when the stone glows. Selected for our World 100 as one of the world''s most dramatic and photogenic ancient cities.' WHERE category = 'attractions' AND title_en = 'Petra';

UPDATE challenges SET description_en = 'The Pyramids of Giza are the only surviving wonder of the ancient world. The Great Pyramid of Khufu was built around 2560 BC and was the tallest human-made structure for nearly 4,000 years. The Sphinx guards the plateau. Selected for our World 100 as the ultimate symbol of ancient Egyptian civilization and human achievement.' WHERE category = 'attractions' AND title_en = 'Pyramids of Giza';

UPDATE challenges SET description_en = 'The Sistine Chapel in Vatican City holds Michelangelo''s ceiling frescoes (1508–1512) and the Last Judgment behind the altar. The ceiling depicts Creation and the prophets; the chapel is the site of papal conclaves. Selected for our World 100 as the greatest single work of Renaissance painting and a spiritual and artistic pilgrimage.' WHERE category = 'attractions' AND title_en = 'Sistine Chapel & Vatican';

UPDATE challenges SET description_en = 'Zhangjiajie National Forest Park in Hunan features towering sandstone pillars that inspired the floating mountains in the film Avatar. The glass bridge, cable cars, and Tianmen Mountain add to the experience. Selected for our World 100 as one of the world''s most surreal and cinematic natural landscapes.' WHERE category = 'attractions' AND title_en = 'Zhangjiajie National Forest Park';

UPDATE challenges SET description_en = 'The Abu Simbel temples in southern Egypt were built by Ramesses II around 1264 BC and were relocated in the 1960s to save them from Nile flooding. The four colossal seated figures and the inner halls are masterpieces of ancient Egyptian architecture. Selected for our World 100 as one of the most dramatic temple rescues and Nubian monuments.' WHERE category = 'attractions' AND title_en = 'Abu Simbel Temples';

UPDATE challenges SET description_en = 'The Alhambra in Granada is a 14th-century Moorish fortress-palace complex with intricate Nasrid plasterwork, courtyards, and fountains. The Generalife gardens and the views over the city complete the experience. Selected for our World 100 as the finest surviving example of Islamic architecture in Europe.' WHERE category = 'attractions' AND title_en = 'Alhambra Palace';

UPDATE challenges SET description_en = 'Arashiyama Bamboo Grove in Kyoto is a path through towering bamboo that creates an ethereal light and sound. Best visited in the morning; combine with Tenryu-ji Temple and the nearby river. Selected for our World 100 as one of Japan''s most iconic and meditative landscapes.' WHERE category = 'attractions' AND title_en = 'Arashiyama Bamboo Grove';

UPDATE challenges SET description_en = 'Borobudur in Java is the world''s largest Buddhist stupa, built in the 9th century. It has 2,672 relief panels and 504 Buddha statues in a mandala layout. Sunrise from the top is magical. Selected for our World 100 as the greatest Buddhist monument in the Southern Hemisphere.' WHERE category = 'attractions' AND title_en = 'Borobudur Temple';

UPDATE challenges SET description_en = 'Cappadocia in central Turkey is a landscape of fairy chimneys, cave dwellings, and underground cities. Hot-air ballooning at sunrise is the signature experience; hiking and cave hotels add to the wonder. Selected for our World 100 as one of the world''s most unique and romantic landscapes.' WHERE category = 'attractions' AND title_en = 'Cappadocia';

UPDATE challenges SET description_en = 'Chichen Itza in Yucatán is a pre-Columbian Maya city and UNESCO site. El Castillo pyramid creates a serpent shadow at the equinox; the Great Ball Court and Sacred Cenote are equally impressive. Selected for our World 100 as the most iconic and accessible Maya archaeological site.' WHERE category = 'attractions' AND title_en = 'Chichen Itza';

UPDATE challenges SET description_en = 'The Great Barrier Reef is the world''s largest coral reef system, stretching over 2,300 km off Queensland. It is visible from space and home to 1,500 species of fish, turtles, and sharks. Snorkeling and diving here are bucket-list experiences. Selected for our World 100 as the greatest marine ecosystem and natural wonder.' WHERE category = 'attractions' AND title_en = 'Great Barrier Reef';

UPDATE challenges SET description_en = 'Ha Long Bay in Vietnam features over 1,600 limestone karst islands in emerald water. UNESCO-listed; kayaking and overnight junk cruises pass floating villages and caves. Selected for our World 100 as one of the world''s most magical seascapes and a symbol of Vietnamese beauty.' WHERE category = 'attractions' AND title_en = 'Ha Long Bay';

UPDATE challenges SET description_en = 'The Hiroshima Peace Memorial (Genbaku Dome) is the skeletal ruin of the building that survived the atomic bomb in 1945. It stands as a UNESCO symbol of peace and a moving reminder of the cost of war. Selected for our World 100 as one of the most important and sobering memorials of the 20th century.' WHERE category = 'attractions' AND title_en = 'Hiroshima Peace Memorial (Genbaku Dome)';

UPDATE challenges SET description_en = 'Jungfraujoch – Top of Europe is the highest railway station in Europe at 3,454 m in the Swiss Bernese Alps. The journey and the glacier panorama, ice palace, and views of the Eiger and Mönch are unforgettable. Selected for our World 100 as the most spectacular alpine railway and viewpoint.' WHERE category = 'attractions' AND title_en = 'Jungfraujoch Top of Europe';

UPDATE challenges SET description_en = 'Komodo National Park in Indonesia is the only home of the Komodo dragon and also features pink sand beaches and pristine reef. Diving and trekking to see the dragons are the highlights. Selected for our World 100 as the only place on Earth to see the world''s largest lizard in the wild.' WHERE category = 'attractions' AND title_en = 'Komodo National Park';

UPDATE challenges SET description_en = 'Maasai Mara National Reserve in Kenya is one of Africa''s greatest wildlife destinations. The annual wildebeest migration (July–October) and year-round Big Five viewing make it iconic. Selected for our World 100 as the greatest stage for the greatest wildlife show on Earth.' WHERE category = 'attractions' AND title_en = 'Maasai Mara National Reserve';

UPDATE challenges SET description_en = 'The Matterhorn is the 4,478 m iconic pyramidal peak on the Swiss–Italian border, with Zermatt at its base. It is the most photographed mountain in the Alps and a symbol of mountaineering. Selected for our World 100 as the world''s most recognizable and majestic mountain.' WHERE category = 'attractions' AND title_en = 'Matterhorn';

UPDATE challenges SET description_en = 'Meteora in Greece is a complex of Byzantine monasteries perched on impossible rock pinnacles. UNESCO-listed; sunset views and visits to the surviving monasteries are unforgettable. Selected for our World 100 as one of the most dramatic and spiritual landscapes on Earth.' WHERE category = 'attractions' AND title_en = 'Meteora Monasteries';

UPDATE challenges SET description_en = 'Sossusvlei and the Namib Desert in Namibia feature the world''s tallest red sand dunes (over 300 m) and the ghost trees of Dead Vlei. The desert is among the oldest on Earth. Selected for our World 100 as the most photogenic and surreal desert landscape.' WHERE category = 'attractions' AND title_en = 'Sossusvlei & Namib Desert';

UPDATE challenges SET description_en = 'Torres del Paine in Chilean Patagonia is a national park of granite towers, glaciers, pumas, condors, and guanacos. The W Trek and boat trips to Grey Glacier are world-class. Selected for our World 100 as the most dramatic and accessible Patagonian wilderness.' WHERE category = 'attractions' AND title_en = 'Torres del Paine Patagonia';

UPDATE challenges SET description_en = 'Serengeti National Park in Tanzania is the stage for the annual migration of 1.5 million wildebeest and countless predators. UNESCO biosphere; endless savanna and luxury lodges. Selected for our World 100 as the greatest African savanna ecosystem and wildlife destination.' WHERE category = 'attractions' AND title_en = 'Serengeti National Park';

UPDATE challenges SET description_en = 'Sigiriya Rock Fortress in Sri Lanka is a 5th-century citadel on a 200 m granite rock. Frescoes, mirror wall, and water gardens survive; the lion gate and summit views are spectacular. Selected for our World 100 as one of the most dramatic and mysterious ancient fortress sites.' WHERE category = 'attractions' AND title_en = 'Sigiriya Rock Fortress';

UPDATE challenges SET description_en = 'The Stone Forest (Shilin) in Yunnan is a 270 million-year-old karst landscape of stone pillars. UNESCO-listed; Sani Yi culture and walking paths make it a unique experience. Selected for our World 100 as one of the world''s most unusual and ancient karst formations.' WHERE category = 'attractions' AND title_en = 'Stone Forest Shilin';

UPDATE challenges SET description_en = 'Tanah Lot is a Balinese sea temple on a rocky islet, accessible at low tide. Sunset views and the sound of the waves make it one of Bali''s most iconic landmarks. Selected for our World 100 as the most photogenic and spiritual sea temple in Indonesia.' WHERE category = 'attractions' AND title_en = 'Tanah Lot Temple';

UPDATE challenges SET description_en = 'The Terracotta Army in Xi''an comprises 8,000 life-sized clay soldiers guarding the tomb of China''s first emperor, Qin Shi Huang. Discovered in 1974, each figure is unique. Selected for our World 100 as one of the greatest archaeological discoveries and imperial treasures.' WHERE category = 'attractions' AND title_en = 'Terracotta Army';

UPDATE challenges SET description_en = 'Uluru (Ayers Rock) is the sacred 348 m sandstone monolith in Australia''s Red Centre. Anangu culture and the changing colors at sunrise and sunset make it a spiritual and visual icon. Selected for our World 100 as the world''s most iconic natural and cultural landmark of Australia.' WHERE category = 'attractions' AND title_en = 'Uluru (Ayers Rock)';

UPDATE challenges SET description_en = 'Victoria Falls on the Zambia–Zimbabwe border is the world''s largest sheet of falling water (1,708 m wide). Devil''s Pool on the edge and helicopter flights offer unforgettable perspectives. Selected for our World 100 as the most dramatic and accessible major waterfall on Earth.' WHERE category = 'attractions' AND title_en = 'Victoria Falls';

UPDATE challenges SET description_en = 'The Amalfi Coast in Italy is a UNESCO-listed stretch of dramatic cliffs, colorful villages, and lemon groves. Positano, Amalfi, and Ravello are highlights; limoncello and sea views define the experience. Selected for our World 100 as the most romantic and iconic Mediterranean coastline.' WHERE category = 'attractions' AND title_en = 'Amalfi Coast';

UPDATE challenges SET description_en = 'The Anne Frank House in Amsterdam is the building where Anne Frank and her family hid during the Nazi occupation. Her diary and the preserved secret annex offer a moving encounter with history. Selected for our World 100 as one of the most important and humanizing Holocaust memorials.' WHERE category = 'attractions' AND title_en = 'Anne Frank House';

UPDATE challenges SET description_en = 'Jatiluwih Rice Terraces in Bali are a UNESCO cultural landscape with subak irrigation and green staircases of rice paddies. Walking and cycling through the terraces reveal traditional farming. Selected for our World 100 as the most beautiful and culturally significant rice terraces in Southeast Asia.' WHERE category = 'attractions' AND title_en = 'Jatiluwih Rice Terraces Bali';

UPDATE challenges SET description_en = 'The Sultan Ahmed Mosque (Blue Mosque) in Istanbul is an Ottoman masterpiece from 1616 with six minarets and over 20,000 Iznik blue tiles. Active worship and visitor hours are coordinated. Selected for our World 100 as one of the world''s most beautiful and iconic mosques.' WHERE category = 'attractions' AND title_en = 'Sultan Ahmed Mosque (Blue Mosque)';

UPDATE challenges SET description_en = 'The Brandenburg Gate in Berlin is an 18th-century neoclassical triumphal arch and the symbol of German reunification. The Pariser Platz and surrounding history make it the heart of the capital. Selected for our World 100 as Europe''s most symbolic and historically charged monument.' WHERE category = 'attractions' AND title_en = 'Brandenburg Gate';

UPDATE challenges SET description_en = 'Burj Khalifa in Dubai is the world''s tallest building at 828 m. At the Top observation decks and the outdoor Sky level offer panoramic views of the city and desert. Selected for our World 100 as the ultimate symbol of 21st-century ambition and urban spectacle.' WHERE category = 'attractions' AND title_en = 'Burj Khalifa';

UPDATE challenges SET description_en = 'Château de Chambord in the Loire Valley is the largest and most recognizable French Renaissance château. The double-helix staircase attributed to Leonardo da Vinci is a masterpiece. Selected for our World 100 as the greatest Loire château and a symbol of royal grandeur.' WHERE category = 'attractions' AND title_en = 'Chateau de Chambord';

UPDATE challenges SET description_en = 'Christ the Redeemer is the 30 m art deco statue of Jesus on Corcovado Mountain (709 m) overlooking Rio de Janeiro. The panoramic view of the harbour and city is iconic. Selected for our World 100 as the most recognizable and spiritual landmark of South America.' WHERE category = 'attractions' AND title_en = 'Christ the Redeemer';

UPDATE challenges SET description_en = 'The Colosseum in Rome is the ancient amphitheater completed in 80 AD, with a capacity of around 80,000. Gladiatorial games and public spectacles were held here. Selected for our World 100 as the greatest surviving symbol of ancient Rome and the classical world.' WHERE category = 'attractions' AND title_en = 'Colosseum';

UPDATE challenges SET description_en = 'Edinburgh Castle dominates the skyline from its volcanic rock. The Crown Jewels, Stone of Destiny, and One O''clock Gun are highlights; the views over the city are unforgettable. Selected for our World 100 as the most dramatic and historic fortress in Britain.' WHERE category = 'attractions' AND title_en = 'Edinburgh Castle';

UPDATE challenges SET description_en = 'The Eiffel Tower in Paris is the 330 m iron lattice tower built for the 1889 World''s Fair. It receives millions of visitors yearly; the night light show and views define the Paris experience. Selected for our World 100 as the world''s most iconic tower and symbol of a city.' WHERE category = 'attractions' AND title_en = 'Eiffel Tower';

UPDATE challenges SET description_en = 'Ephesus in Turkey is one of the best-preserved Greco-Roman cities. The Library of Celsus façade, the Great Theatre, and the Terrace Houses are highlights. Selected for our World 100 as the finest ancient city ruins in the Eastern Mediterranean.' WHERE category = 'attractions' AND title_en = 'Ephesus Ancient City';

UPDATE challenges SET description_en = 'The Forbidden City in Beijing is the 600-year-old imperial palace complex with over 9,000 rooms, surrounded by a moat and walls. It was the seat of Chinese emperors for five centuries. Selected for our World 100 as the world''s largest and most significant palace complex.' WHERE category = 'attractions' AND title_en = 'Forbidden City';

UPDATE challenges SET description_en = 'Fushimi Inari Taisha in Kyoto is the shrine famous for thousands of vermilion torii gates winding up Mount Inari. A dawn or evening hike through the gates is a quintessential Japanese experience. Selected for our World 100 as the most iconic and atmospheric shrine path in Japan.' WHERE category = 'attractions' AND title_en = 'Fushimi Inari Taisha';

UPDATE challenges SET description_en = 'The Golden Gate Bridge in San Francisco is the 1937 suspension bridge across the entrance to the bay. Walking or cycling across offers iconic views of the city and Pacific. Selected for our World 100 as the most photographed and beloved bridge in the world.' WHERE category = 'attractions' AND title_en = 'Golden Gate Bridge';

UPDATE challenges SET description_en = 'The Grand Canyon in Arizona is up to 1.6 km deep and 446 km long. South Rim sunset and the Bright Angel Trail are classic experiences. Selected for our World 100 as the world''s most awe-inspiring and accessible canyon.' WHERE category = 'attractions' AND title_en = 'Grand Canyon';

UPDATE challenges SET description_en = 'The Grand Palace in Bangkok is the opulent royal complex that includes Wat Phra Kaew (Emerald Buddha) and the Chakri Hall. Dress codes and crowds are part of the experience. Selected for our World 100 as the most dazzling and sacred royal site in Southeast Asia.' WHERE category = 'attractions' AND title_en = 'Grand Palace Bangkok';

UPDATE challenges SET description_en = 'Hagia Sophia in Istanbul was built in 537 AD as a Byzantine church; its 55 m dome and gold mosaics are legendary. Now an active mosque, it remains a symbol of East and West. Selected for our World 100 as one of the greatest architectural and religious buildings in history.' WHERE category = 'attractions' AND title_en = 'Hagia Sophia';

UPDATE challenges SET description_en = 'Hoi An Ancient Town in Vietnam is a UNESCO trading port with the Japanese Bridge, lantern-lit streets, and tailors. The mix of cultures and preservation makes it magical. Selected for our World 100 as Southeast Asia''s most charming and photogenic old town.' WHERE category = 'attractions' AND title_en = 'Hoi An Ancient Town';

UPDATE challenges SET description_en = 'Kinkaku-ji (Golden Pavilion) in Kyoto is a Zen temple covered in gold leaf, reflected in the Mirror Pond. The garden and pavilion are iconic in every season. Selected for our World 100 as Japan''s most beautiful and iconic temple.' WHERE category = 'attractions' AND title_en = 'Kinkaku-ji Golden Pavilion';

UPDATE challenges SET description_en = 'The Li River and Guilin in China offer a karst peak cruise that appears on the 20-yuan note. Bamboo raft or boat trips pass through a landscape of pillars and mist. Selected for our World 100 as the most iconic and poetic river landscape in China.' WHERE category = 'attractions' AND title_en = 'Li River & Guilin';

UPDATE challenges SET description_en = 'The Louvre in Paris is the world''s largest art museum, with over 35,000 works including the Mona Lisa and Venus de Milo. The palace and glass pyramid are landmarks. Selected for our World 100 as the world''s most visited and comprehensive art museum.' WHERE category = 'attractions' AND title_en = 'Louvre Museum';

UPDATE challenges SET description_en = 'Masada in Israel is Herod''s 1st-century fortress on a plateau above the Dead Sea. The Roman siege ramp and the story of the Jewish rebels make it a powerful symbol. Selected for our World 100 as one of the most dramatic and meaningful archaeological and memorial sites.' WHERE category = 'attractions' AND title_en = 'Masada Fortress';

UPDATE challenges SET description_en = 'The Moai statues on Easter Island (Rapa Nui) are 887 monolithic figures carved by the Rapa Nui people. Rano Raraku quarry and the coastal platforms are unforgettable. Selected for our World 100 as the world''s most mysterious and remote monumental statues.' WHERE category = 'attractions' AND title_en = 'Moai Statues Easter Island';

UPDATE challenges SET description_en = 'Mont Saint-Michel in Normandy is a tidal island with a medieval abbey, UNESCO-listed. The causeway, sand flats, and pilgrim history create a fairy-tale setting. Selected for our World 100 as the most dramatic and iconic tidal island and abbey in Europe.' WHERE category = 'attractions' AND title_en = 'Mont Saint-Michel';

UPDATE challenges SET description_en = 'Mount Fuji is Japan''s iconic 3,776 m stratovolcano and UNESCO site. The climbing season is July–September; views from the lakes and from Tokyo are iconic. Selected for our World 100 as the world''s most recognizable and sacred volcano.' WHERE category = 'attractions' AND title_en = 'Mount Fuji';

UPDATE challenges SET description_en = 'Neuschwanstein Castle in Bavaria is the 19th-century fairy-tale castle that inspired Disney''s Sleeping Beauty. The views from Marienbrücke and the interior are spectacular. Selected for our World 100 as the most romantic and iconic castle in the world.' WHERE category = 'attractions' AND title_en = 'Neuschwanstein Castle';

UPDATE challenges SET description_en = 'Niagara Falls on the Canada–US border comprises three waterfalls. Maid of the Mist and Journey Behind the Falls offer close-up experiences. Selected for our World 100 as the most powerful and accessible major waterfall in North America.' WHERE category = 'attractions' AND title_en = 'Niagara Falls';

UPDATE challenges SET description_en = 'Notre Dame Cathedral in Paris is the Gothic masterpiece begun in 1163, with gargoyles and rose windows. Damaged by fire in 2019, it has been restored and reopened. Selected for our World 100 as the most iconic Gothic cathedral and symbol of Paris.' WHERE category = 'attractions' AND title_en = 'Notre Dame Cathedral';

UPDATE challenges SET description_en = 'Pamukkale (Cotton Castle) in Turkey is a series of white travertine terraces formed by thermal waters. The ancient city of Hierapolis and the sacred pools are part of the visit. Selected for our World 100 as the most striking and surreal thermal landscape.' WHERE category = 'attractions' AND title_en = 'Pamukkale Cotton Castle';

UPDATE challenges SET description_en = 'Park Güell in Barcelona is Gaudí''s colourful mosaic park with the dragon staircase, serpentine bench, and views over the city. A UNESCO site and symbol of Catalan modernism. Selected for our World 100 as the most playful and iconic public park in the world.' WHERE category = 'attractions' AND title_en = 'Park Guell';

UPDATE challenges SET description_en = 'The Parthenon on the Acropolis in Athens is the 5th-century BC temple dedicated to Athena. The hilltop and the museum below hold the legacy of classical Greece. Selected for our World 100 as the greatest symbol of Western civilization and democracy.' WHERE category = 'attractions' AND title_en = 'Parthenon & Acropolis';

UPDATE challenges SET description_en = 'Piazza San Marco in Venice is the heart of the city, with St Mark''s Basilica, the Campanile, and the Doge''s Palace. Pigeons, cafés, and floods (acqua alta) are part of the legend. Selected for our World 100 as the world''s most famous and romantic square.' WHERE category = 'attractions' AND title_en = 'Piazza San Marco';

UPDATE challenges SET description_en = 'Pompeii near Naples is the ancient Roman city buried by Vesuvius in 79 AD. Streets, houses, and frescoes are remarkably preserved. Selected for our World 100 as the most complete and moving snapshot of Roman daily life.' WHERE category = 'attractions' AND title_en = 'Pompeii';

UPDATE challenges SET description_en = 'Prague Old Town Square features the Astronomical Clock (1410), the Church of Our Lady before Týn, and baroque buildings. The heart of the historic centre. Selected for our World 100 as Europe''s most picturesque and atmospheric old town square.' WHERE category = 'attractions' AND title_en = 'Prague Old Town Square';

UPDATE challenges SET description_en = 'La Sagrada Familia in Barcelona is Gaudí''s unfinished basilica, under construction since 1882. The 18 towers, organic forms, and stained glass create an otherworldly interior. Selected for our World 100 as the most unique and ambitious religious building of the modern era.' WHERE category = 'attractions' AND title_en = 'Sagrada Familia';

UPDATE challenges SET description_en = 'Santorini Caldera is the volcanic island with blue-dome churches in Oia, wine tasting, and caldera cruises. Sunsets and white villages define the postcard. Selected for our World 100 as the most romantic and iconic Greek island landscape.' WHERE category = 'attractions' AND title_en = 'Santorini Caldera';

UPDATE challenges SET description_en = 'Senso-ji in Tokyo is the city''s oldest and most colourful temple, with the Nakamise shopping street and Thunder Gate. A quintessential Tokyo experience. Selected for our World 100 as the most iconic and atmospheric temple complex in Japan''s capital.' WHERE category = 'attractions' AND title_en = 'Senso-ji Temple';

UPDATE challenges SET description_en = 'Sheikh Zayed Grand Mosque in Abu Dhabi is one of the world''s largest mosques, with 82 domes and gold-leaf minarets. Dress code and guided visits are available. Selected for our World 100 as the most opulent and photogenic modern mosque.' WHERE category = 'attractions' AND title_en = 'Sheikh Zayed Grand Mosque';

UPDATE challenges SET description_en = 'Shwedagon Pagoda in Yangon is a gilded Buddhist stupa said to be 2,500 years old, with 27 tonnes of gold. The 326 m structure dominates the skyline. Selected for our World 100 as the most sacred and dazzling Buddhist monument in Southeast Asia.' WHERE category = 'attractions' AND title_en = 'Shwedagon Pagoda';

UPDATE challenges SET description_en = 'The Great Sphinx of Giza is the limestone monolith 73 m long with a human head and lion body, guarding the Khafre pyramid. Selected for our World 100 as the world''s most iconic and mysterious monumental sculpture.' WHERE category = 'attractions' AND title_en = 'Great Sphinx of Giza';

UPDATE challenges SET description_en = 'St Basil''s Cathedral on Red Square in Moscow is the colourful onion-domed church built in 1561. It is the symbol of Russia and Red Square. Selected for our World 100 as the most recognizable and whimsical cathedral in the world.' WHERE category = 'attractions' AND title_en = 'St Basil''s Cathedral';

UPDATE challenges SET description_en = 'St Peter''s Basilica in Vatican City is the Renaissance masterpiece with Michelangelo''s dome and the Pietà. The square and the papal altar are the heart of Catholicism. Selected for our World 100 as the largest and most significant church in Christendom.' WHERE category = 'attractions' AND title_en = 'St Peter''s Basilica';

UPDATE challenges SET description_en = 'The Statue of Liberty in New York Harbor was a gift from France in 1886. Liberty Island and crown access offer views and symbolism of freedom. Selected for our World 100 as the world''s most iconic symbol of freedom and immigration.' WHERE category = 'attractions' AND title_en = 'Statue of Liberty';

UPDATE challenges SET description_en = 'Stonehenge in England is the prehistoric stone circle dating to around 3000 BC. The summer solstice alignment and the visitor centre tell the story of the mystery. Selected for our World 100 as the world''s most famous and enigmatic prehistoric monument.' WHERE category = 'attractions' AND title_en = 'Stonehenge';

UPDATE challenges SET description_en = 'The Sydney Opera House on Bennelong Point is Jørn Utzon''s UNESCO-listed expressionist design. Tours and performances define the harbour. Selected for our World 100 as the most iconic and recognizable building of the 20th century.' WHERE category = 'attractions' AND title_en = 'Sydney Opera House';

UPDATE challenges SET description_en = 'The Taj Mahal in Agra is the white marble UNESCO mausoleum built in 1653, with reflecting pool and inlaid gems. A monument to love and Mughal art. Selected for our World 100 as the most beautiful and romantic building in the world.' WHERE category = 'attractions' AND title_en = 'Taj Mahal';

UPDATE challenges SET description_en = 'Tanah Lot Sunset Tour combines the Bali sea temple with traditional Kecak fire dance performance. Sunset and culture in one experience. Selected for our World 100 as the most iconic and atmospheric cultural performance setting in Bali.' WHERE category = 'attractions' AND title_en = 'Tanah Lot Sunset Tour';

UPDATE challenges SET description_en = 'The Temple of Heaven in Beijing is the Ming-era imperial sacrificial complex with the Echo Wall and Hall of Prayer for Good Harvests. Selected for our World 100 as the finest example of Chinese imperial ritual architecture.' WHERE category = 'attractions' AND title_en = 'Temple of Heaven';

UPDATE challenges SET description_en = 'Tokyo Skytree is the world''s tallest tower at 634 m, with two observation decks and the Tembo Galleria. A symbol of modern Tokyo. Selected for our World 100 as the most impressive and accessible urban observation tower.' WHERE category = 'attractions' AND title_en = 'Tokyo Skytree';

UPDATE challenges SET description_en = 'The Tower of London is the 11th-century castle that holds the Crown Jewels, Beefeater tours, and the raven legend. The history of monarchy and imprisonment. Selected for our World 100 as the most historic and atmospheric fortress in England.' WHERE category = 'attractions' AND title_en = 'Tower of London';

UPDATE challenges SET description_en = 'The Uffizi Gallery in Florence holds the greatest Renaissance collection: Botticelli''s Birth of Venus, Raphael, and more. A pilgrimage for art lovers. Selected for our World 100 as the world''s greatest repository of Renaissance painting.' WHERE category = 'attractions' AND title_en = 'Uffizi Gallery';

UPDATE challenges SET description_en = 'The Palace of Versailles near Paris is the royal château with the Hall of Mirrors and 800-hectare gardens with fountain shows. The symbol of French royal power. Selected for our World 100 as the most opulent and influential palace in European history.' WHERE category = 'attractions' AND title_en = 'Palace of Versailles';

UPDATE challenges SET description_en = 'Victoria Peak in Hong Kong is reached by the Peak Tram; the summit offers the classic city skyline and harbour view, especially at night. Selected for our World 100 as the most iconic urban viewpoint in Asia.' WHERE category = 'attractions' AND title_en = 'Victoria Peak Hong Kong';

UPDATE challenges SET description_en = 'The Western Wall in Jerusalem is Judaism''s holiest prayer site. Prayer notes in the cracks and the atmosphere of the Old City make it unforgettable. Selected for our World 100 as the most sacred and emotionally powerful Jewish site.' WHERE category = 'attractions' AND title_en = 'Western Wall Jerusalem';

UPDATE challenges SET description_en = 'Wat Pho in Bangkok is the Temple of the Reclining Buddha (46 m long, 15 m high) and the birthplace of traditional Thai massage. Selected for our World 100 as Bangkok''s most impressive and culturally rich temple.' WHERE category = 'attractions' AND title_en = 'Wat Pho Temple of Reclining Buddha';

UPDATE challenges SET description_en = 'Yellowstone National Park was the world''s first national park. Old Faithful geyser, Grand Prismatic Spring, and wildlife define the American wilderness. Selected for our World 100 as the greatest concentration of geothermal and wildlife wonders in North America.' WHERE category = 'attractions' AND title_en = 'Yellowstone National Park';
